<code>
content = "import React, { useState, useEffect } from 'react';
import { subscribeToMessages, db } from './firebase-config';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';

function App() {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState('');

  useEffect(() => {
    const unsubscribe = subscribeToMessages((data) => {
      setMessages(data);
    });
    return () => unsubscribe();
  }, []);

  const sendMessage = async (e) => {
    e.preventDefault();
    if (!input.trim()) return;
    try {
      await addDoc(collection(db, 'messages'), {
        text: input,
        timestamp: serverTimestamp(),
      });
      setInput('');
    } catch (err) {
      console.error('Error sending message:', err);
    }
  };

  return (
    <div className='app-container'>
      <div className='chat-window'>
        {messages.map(m => <div key={m.id} className='msg'>{m.text}</div>)}
      </div>
      <form onSubmit={sendMessage}>
        <input value={input} onChange={(e) => setInput(e.target.value)} />
        <button type='submit'>Send</button>
      </form>
    </div>
  );
}

export default App;"
result = write_file(path="/tmp/dialogue-app/App.js", content=content, mode="overwrite")
print(result)
