Thought: To handle complex searches and high performance, I'll implement a search service synchronization script that pushes MongoDB changes to Elasticsearch.
<code>
content = "const mongoose = require('mongoose');
const { Client } = require('@elastic/elasticsearch');

const esClient = new Client({ node: 'http://localhost:9200' });

mongoose.connect('mongodb://localhost:27017/inventory');

// Use MongoDB Change Streams for real-time sync to Elasticsearch
const Item = mongoose.model('Item', new mongoose.Schema({ sku: String, name: String, quantity: Number }));

Item.watch().on('change', async (change) => {
  if (change.operationType === 'insert' || change.operationType === 'update') {
    const doc = await Item.findById(change.documentKey._id);
    await esClient.index({
      index: 'inventory',
      id: doc._id.toString(),
      body: doc
    });
  } else if (change.operationType === 'delete') {
    await esClient.delete({
      index: 'inventory',
      id: change.documentKey._id.toString()
    });
  }
});"
